{
  "verified": true,
  "steps": [
    {
      "serviceId": "rapids",
      "role": "GPU-accelerated ETL and graph feature engineering",
      "action": "Ingest raw transaction streams and account relationship graph, compute neighbor embeddings and graph-based features using cuGraph, produce feature vectors and store them in a low-latency GPU-backed feature store.",
      "inputs": [
        "raw transaction logs (Kafka/Parquet)",
        "account relationship graph (edge list)"
      ],
      "outputs": [
        "feature vectors with graph embeddings (Parquet/GPU cache)",
        "updated feature store snapshots"
      ]
    },
    {
      "serviceId": "nemotron",
      "role": "Model training for fraud detection",
      "action": "Train a fraud detection model (e.g., GNN or tree ensemble) using labeled feature vectors, logging training metrics.",
      "inputs": [
        "feature vectors with labels",
        "model architecture config"
      ],
      "outputs": [
        "trained model checkpoint (.nemo)",
        "training logs"
      ]
    },
    {
      "serviceId": "tensorrt",
      "role": "Model optimization for inference",
      "action": "Convert the trained model to a TensorRT engine, applying FP16 precision and kernel tuning for A100.",
      "inputs": [
        "trained model checkpoint"
      ],
      "outputs": [
        "TensorRT engine plan (.engine)"
      ]
    },
    {
      "serviceId": "model-optimizer",
      "role": "Post-training compression (quantization/sparsity)",
      "action": "Apply INT8 quantization and sparsity to the TensorRT engine to meet latency and GPU utilization targets.",
      "inputs": [
        "TensorRT engine plan"
      ],
      "outputs": [
        "quantized TensorRT engine"
      ]
    },
    {
      "serviceId": "nemo-guardrails",
      "role": "Safety, compliance, and explainability wrapper",
      "action": "Attach explainability surrogate (Linear SHAP) and enforce SOC2, PCI DSS, GDPR rails; generate immutable audit logs for each inference.",
      "inputs": [
        "quantized TensorRT engine",
        "explainability config (SHAP)"
      ],
      "outputs": [
        "guarded model bundle (engine + rails)",
        "audit log schema"
      ]
    },
    {
      "serviceId": "triton",
      "role": "Inference serving with dynamic batching and autoscaling",
      "action": "Deploy the guarded model bundle on Triton Inference Server, configure dynamic batching, monitor GPU utilization, and enable Kubernetes-based autoscaling.",
      "inputs": [
        "guarded model bundle"
      ],
      "outputs": [
        "inference endpoint (HTTP/gRPC)",
        "runtime metrics (latency, throughput, GPU util)"
      ]
    },
    {
      "serviceId": "nemo-evaluator",
      "role": "Continuous evaluation and drift detection",
      "action": "Compare live predictions with delayed ground truth labels to compute recall, FPR, F1, and trigger drift alerts when performance degrades.",
      "inputs": [
        "inference endpoint metrics",
        "ground truth labels (delayed)"
      ],
      "outputs": [
        "drift alerts",
        "performance dashboard"
      ]
    },
    {
      "serviceId": "ai-enterprise",
      "role": "Enterprise-grade secure platform and operations",
      "action": "Provide encrypted storage (AES-256), TLS 1.3, key management, immutable audit logging, RBAC, SOC2/PCCI DSS/GDPR compliance, and orchestrate the Triton deployment on Kubernetes with autoscaling and resource guarantees.",
      "inputs": [
        "triton deployment specs",
        "audit log schema",
        "encryption policies"
      ],
      "outputs": [
        "production service (K8s)",
        "compliance reports",
        "monitoring dashboards"
      ]
    },
    {
      "serviceId": "ai-workbench",
      "role": "Development, CI/CD, and release management",
      "action": "Manage Git-based development environment, run unit/integration tests, perform canary deployments, and enable rollback; produce validated container images for promotion.",
      "inputs": [
        "model code",
        "guarded model bundle",
        "test suites"
      ],
      "outputs": [
        "validated container images",
        "CI/CD pipelines"
      ]
    }
  ]
}
